import boto3

def create_sns_subscription(topic_arn, endpoint_urls):
    sns = boto3.client('sns')

    for endpoint in endpoint_urls:
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        print(f'Subscription ARN: {response["SubscriptionArn"]}')

def main():
    topic_arn = input("Enter the SNS Topic ARN: ")
    endpoints = input("Enter the subscription endpoints (comma-separated): ")
    
    endpoint_urls = [url.strip() for url in endpoints.split(',')]
    create_sns_subscription(topic_arn, endpoint_urls)

if __name__ == "__main__":
    main()